// TicketHistory.jsx
import React, { useEffect, useState } from "react";

const API_BASE = "https://prasa-app-yde3.onrender.com/api/app";
const green = "#0f9d58";
const light = "#eaf8f0";

export default function TicketHistory({ employee }) {
  const [data, setData] = useState([]);
  const [fromDate, setFrom] = useState("");
  const [toDate, setTo] = useState("");

  useEffect(() => {
    if (employee?.empld) fetchData();
  }, [employee]);

  const fetchData = async () => {
    try {
      const empId = employee.empld;
      const res = await fetch(`${API_BASE}/ticket/expenses?empId=${empId}`);
      const result = await res.json();
      const rows = Array.isArray(result) ? result : result.records || result;
      setData(Array.isArray(rows) ? rows : []);
    } catch (err) {
      console.error("Ticket history error:", err);
      setData([]);
    }
  };

  const filtered = data.filter((t) => {
    const d = new Date(t.ticket_date);
    const f = fromDate ? new Date(fromDate) : null;
    const tt = toDate ? new Date(toDate) : null;

    if (f && d < f) return false;
    if (tt && d > tt) return false;
    return true;
  });

  return (
    <div style={{ background: light, minHeight: "100vh", padding: 20 }}>
      <div
        style={{
          maxWidth: 900,
          margin: "0 auto",
          background: "#fff",
          borderRadius: 18,
          padding: 20,
          boxShadow: "0 4px 15px rgba(0,0,0,0.1)",
        }}
      >
        <div style={{ display: "flex", alignItems: "center", gap: 10 }}>
          <button
            onClick={() => window.history.back()}
            style={{
              background: light,
              border: "none",
              padding: "8px 12px",
              borderRadius: 10,
              cursor: "pointer",
            }}
          >
            ←
          </button>
          <h2 style={{ margin: 0, color: green }}>Ticket Expense History</h2>
        </div>

        <p style={{ marginTop: 8, color: "#555" }}>
          Employee: {employee?.name} • {employee?.empld}
        </p>

        <div
          style={{
            marginTop: 15,
            background: light,
            padding: 12,
            borderRadius: 12,
            display: "flex",
            gap: 10,
            flexWrap: "wrap",
          }}
        >
          <div style={{ flex: 1 }}>
            <label>From</label>
            <input
              type="date"
              value={fromDate}
              onChange={(e) => setFrom(e.target.value)}
              style={{ width: "100%", padding: 8, borderRadius: 8, border: "1px solid #ccc" }}
            />
          </div>
          <div style={{ flex: 1 }}>
            <label>To</label>
            <input
              type="date"
              value={toDate}
              onChange={(e) => setTo(e.target.value)}
              style={{ width: "100%", padding: 8, borderRadius: 8, border: "1px solid #ccc" }}
            />
          </div>

          <button
            onClick={fetchData}
            style={{
              alignSelf: "flex-end",
              background: green,
              color: "#fff",
              border: "none",
              padding: "10px 16px",
              borderRadius: 10,
              cursor: "pointer",
            }}
          >
            Reset
          </button>
        </div>

        <div style={{ marginTop: 15 }}>
          <table style={{ width: "100%", borderCollapse: "collapse" }}>
            <thead>
              <tr style={{ background: light }}>
                <th style={{ padding: 8 }}>Date</th>
                <th style={{ padding: 8 }}>Purpose</th>
                <th style={{ padding: 8 }}>Assigned To</th>
                <th style={{ padding: 8 }}>Amount</th>
              </tr>
            </thead>
            <tbody>
              {filtered.length === 0 ? (
                <tr>
                  <td colSpan="4" style={{ textAlign: "center", padding: 20 }}>
                    No data
                  </td>
                </tr>
              ) : (
                filtered.map((t) => (
                  <tr key={t.id}>
                    <td style={{ padding: 8 }}>{t.ticket_date}</td>
                    <td style={{ padding: 8 }}>{t.purpose}</td>
                    <td style={{ padding: 8 }}>{t.assigned_to}</td>
                    <td style={{ padding: 8 }}>₹ {t.amount}</td>
                  </tr>
                ))
              )}
            </tbody>
          </table>
        </div>

        <div style={{ marginTop: 20 }}>
          <button
            style={{
              background: green,
              color: "#fff",
              border: "none",
              padding: "10px 18px",
              borderRadius: 10,
              cursor: "pointer",
            }}
          >
            📄 Download Monthly Report
          </button>
        </div>
      </div>
    </div>
  );
}
